package v1

import (
	"bytes"
	"context"
	"encoding/json"
	"fmt"
	"net/http"
	"net/http/httptest"
	"testing"
	"time"

	"github.com/stretchr/testify/require"
)

// mockSilenceManager is a mock implementation of SilenceManager for testing.
type mockSilenceManager struct {
	ids      []string
	idx      int
	createFn func(sil Silence) (string, error)
}

func (m *mockSilenceManager) CreateSilence(sil Silence) (string, error) {
	if m.createFn != nil {
		return m.createFn(sil)
	}
	if m.idx < len(m.ids) {
		id := m.ids[m.idx]
		m.idx++
		return id, nil
	}
	return fmt.Sprintf("silence-%d", m.idx), nil
}

// newValidSilence creates a valid silence for testing.
func newValidSilence(i int) Silence {
	now := time.Now()
	return Silence{
		Matchers: []SilenceMatcher{
			{Name: "alertname", Value: fmt.Sprintf("Alert%d", i), IsRegex: false, IsEqual: true},
		},
		StartsAt:  now,
		EndsAt:    now.Add(time.Hour),
		CreatedBy: "test-user",
		Comment:   fmt.Sprintf("test silence %d", i),
	}
}

// makeBulkRequest creates an HTTP request with a JSON-encoded array of silences.
func makeBulkRequest(t *testing.T, silences []Silence) *http.Request {
	t.Helper()
	body, err := json.Marshal(silences)
	require.NoError(t, err)
	req := httptest.NewRequest(http.MethodPost, "/api/v1/silences/bulk", bytes.NewReader(body))
	req.Header.Set("Content-Type", "application/json")
	return req.WithContext(context.Background())
}

// TestCreateBulkSilences_Success tests that multiple valid silences are created successfully.
func TestCreateBulkSilences_Success(t *testing.T) {
	api := &API{
		silenceManager: &mockSilenceManager{
			ids: []string{"id-1", "id-2", "id-3"},
		},
	}

	silences := []Silence{
		newValidSilence(1),
		newValidSilence(2),
		newValidSilence(3),
	}

	req := makeBulkRequest(t, silences)
	result := api.createBulkSilences(req)

	require.Nil(t, result.err)
	ids, ok := result.data.([]string)
	require.True(t, ok, "expected data to be []string")
	require.Equal(t, []string{"id-1", "id-2", "id-3"}, ids)
}

// TestCreateBulkSilences_EmptyArray tests that an empty array is handled gracefully.
func TestCreateBulkSilences_EmptyArray(t *testing.T) {
	api := &API{
		silenceManager: &mockSilenceManager{},
	}

	req := makeBulkRequest(t, []Silence{})
	result := api.createBulkSilences(req)

	require.Nil(t, result.err)
	ids, ok := result.data.([]string)
	require.True(t, ok, "expected data to be []string")
	require.Empty(t, ids)
}

// TestCreateBulkSilences_ValidationFailure tests that a silence with no matchers is rejected.
func TestCreateBulkSilences_ValidationFailure(t *testing.T) {
	api := &API{
		silenceManager: &mockSilenceManager{},
	}

	now := time.Now()
	silences := []Silence{
		{
			Matchers:  []SilenceMatcher{}, // empty matchers = invalid
			StartsAt:  now,
			EndsAt:    now.Add(time.Hour),
			CreatedBy: "test-user",
			Comment:   "invalid silence",
		},
	}

	req := makeBulkRequest(t, silences)
	result := api.createBulkSilences(req)

	require.NotNil(t, result.err)
	require.Equal(t, errorBadData, result.err.typ)
}

// TestCreateBulkSilences_BadMatchers tests that a silence with an invalid regex matcher is rejected.
func TestCreateBulkSilences_BadMatchers(t *testing.T) {
	api := &API{
		silenceManager: &mockSilenceManager{},
	}

	now := time.Now()
	silences := []Silence{
		{
			Matchers: []SilenceMatcher{
				{Name: "alertname", Value: "[invalid-regex", IsRegex: true, IsEqual: true},
			},
			StartsAt:  now,
			EndsAt:    now.Add(time.Hour),
			CreatedBy: "test-user",
			Comment:   "silence with bad regex",
		},
	}

	req := makeBulkRequest(t, silences)
	result := api.createBulkSilences(req)

	require.NotNil(t, result.err)
	require.Equal(t, errorBadData, result.err.typ)
	require.Contains(t, result.err.err.Error(), "invalid regex")
}

// TestCreateBulkSilences_PartialValidationFailure tests atomic semantics:
// if one silence is invalid, none should be created.
func TestCreateBulkSilences_PartialValidationFailure(t *testing.T) {
	created := 0
	api := &API{
		silenceManager: &mockSilenceManager{
			createFn: func(sil Silence) (string, error) {
				created++
				return fmt.Sprintf("id-%d", created), nil
			},
		},
	}

	now := time.Now()
	silences := []Silence{
		newValidSilence(1), // valid
		{
			Matchers:  []SilenceMatcher{}, // invalid - no matchers
			StartsAt:  now,
			EndsAt:    now.Add(time.Hour),
			CreatedBy: "test-user",
		},
	}

	req := makeBulkRequest(t, silences)
	result := api.createBulkSilences(req)

	// Should fail because second silence is invalid (atomic validation semantics).
	require.NotNil(t, result.err)
	require.Equal(t, errorBadData, result.err.typ)
	require.Contains(t, result.err.err.Error(), "index 1")

	// No silences should have been created.
	require.Equal(t, 0, created)
}

// TestCreateBulkSilences_NoSilenceManager tests that missing silence manager returns an error.
func TestCreateBulkSilences_NoSilenceManager(t *testing.T) {
	api := &API{
		silenceManager: nil,
	}

	req := makeBulkRequest(t, []Silence{newValidSilence(1)})
	result := api.createBulkSilences(req)

	require.NotNil(t, result.err)
	require.Equal(t, errorUnavailable, result.err.typ)
}

// TestCreateBulkSilences_InvalidTimeRange tests that a silence with endsAt before startsAt is rejected.
func TestCreateBulkSilences_InvalidTimeRange(t *testing.T) {
	api := &API{
		silenceManager: &mockSilenceManager{},
	}

	now := time.Now()
	silences := []Silence{
		{
			Matchers: []SilenceMatcher{
				{Name: "alertname", Value: "TestAlert", IsRegex: false, IsEqual: true},
			},
			StartsAt:  now.Add(time.Hour), // starts after ends
			EndsAt:    now,                // ends before starts
			CreatedBy: "test-user",
			Comment:   "invalid time range",
		},
	}

	req := makeBulkRequest(t, silences)
	result := api.createBulkSilences(req)

	require.NotNil(t, result.err)
	require.Equal(t, errorBadData, result.err.typ)
}

