1857: 	w.Header().Set("Cache-Control", "no-cache")
1858: 	w.Header().Set("Connection", "keep-alive")
1859: 
1860: 	// Subscribe to notifications.
1861: 	notifications, unsubscribe, ok := api.notificationsSub()
1862: 	if !ok {
1863: 		w.WriteHeader(http.StatusNoContent)
1864: 		return
1865: 	}
1866: 	defer unsubscribe()
1867: 
1868: 	// Set up a flusher to push the response to the client.
1869: 	flusher, ok := w.(http.Flusher)
1870: 	if !ok {
1871: 		http.Error(w, "Streaming unsupported", http.StatusInternalServerError)
1872: 		return
1873: 	}
1874: 
1875: 	// Flush the response to ensure the headers are immediately and eventSource
1876: 	// onopen is triggered client-side.
1877: 	flusher.Flush()
1878: 
1879: 	for {
1880: 		select {
1881: 		case notification := <-notifications:
1882: 			// Marshal the notification to JSON.
1883: 			jsonData, err := json.Marshal(notification)
1884: 			if err != nil {
