1886: 				continue
1887: 			}
1888: 
1889: 			// Write the event data in SSE format with JSON content.
1890: 			fmt.Fprintf(w, "data: %s\n\n", jsonData)
1891: 
1892: 			// Flush the response to ensure the data is sent immediately.
1893: 			flusher.Flush()
1894: 		case <-r.Context().Done():
