1076: // original host, making sure that IPv6 addresses are not surrounded by square
1077: // brackets.
1078: func sanitizeSplitHostPort(input string) (string, string, error) {
1079: 	host, port, err := net.SplitHostPort(input)
1080: 	if err != nil && strings.HasSuffix(err.Error(), "missing port in address") {
