1092: 	if err != nil {
1093: 		return u, err
1094: 	}
1095: 
1096: 	for _, lhr := range LocalhostRepresentations {
1097: 		if host == lhr {
1098: 			_, ownPort, err := net.SplitHostPort(opts.ListenAddress)
1099: 			if err != nil {
1100: 				return u, err
1101: 			}
1102: 
1103: 			if port == ownPort {
1104: 				// Only in the case where the target is on localhost and its port is
1105: 				// the same as the one we're listening on, we know for sure that
1106: 				// we're monitoring our own process and that we need to change the
1107: 				// scheme, hostname, and port to the externally reachable ones as
1108: 				// well. We shouldn't need to touch the path at all, since if a
1109: 				// path prefix is defined, the path under which we scrape ourselves
1110: 				// should already contain the prefix.
