// SilenceMatcher defines a label matcher for a silence.
type SilenceMatcher struct {
	Name    string `json:"name"`
	Value   string `json:"value"`
	IsRegex bool   `json:"isRegex"`
	IsEqual bool   `json:"isEqual"`
}

// Silence defines a silence entry.
type Silence struct {
	ID        string           `json:"id,omitempty"`
	Matchers  []SilenceMatcher `json:"matchers"`
	StartsAt  time.Time        `json:"startsAt"`
	EndsAt    time.Time        `json:"endsAt"`
	CreatedBy string           `json:"createdBy"`
	Comment   string           `json:"comment"`
}

// SilenceManager is the interface for creating and managing silences.
type SilenceManager interface {
	CreateSilence(sil Silence) (string, error)
}

// validateSilence validates a single silence definition.
// Returns an error if the silence is invalid.
func validateSilence(s Silence) error {
	if len(s.Matchers) == 0 {
		return errors.New("at least one matcher is required")
	}
	for _, m := range s.Matchers {
		if m.Name == "" {
			return errors.New("matcher name cannot be empty")
		}
		if m.IsRegex {
			if _, err := regexp.Compile(m.Value); err != nil {
				return fmt.Errorf("invalid regex in matcher %q: %w", m.Name, err)
			}
		}
	}
	if s.StartsAt.IsZero() {
		return errors.New("startsAt is required")
	}
	if s.EndsAt.IsZero() {
		return errors.New("endsAt is required")
	}
	if !s.EndsAt.After(s.StartsAt) {
		return errors.New("endsAt must be after startsAt")
	}
	return nil
}

// createBulkSilences handles POST /api/v1/silences/bulk.
// It accepts an array of silence definitions, validates all of them atomically,
// and creates them all. Returns an array of created silence IDs on success.
func (api *API) createBulkSilences(r *http.Request) apiFuncResult {
	if api.silenceManager == nil {
		return apiFuncResult{nil, &apiError{errorUnavailable, errors.New("silence manager not configured")}, nil, nil}
	}

	var silences []Silence
	if err := json.NewDecoder(r.Body).Decode(&silences); err != nil {
		return apiFuncResult{nil, &apiError{errorBadData, fmt.Errorf("error decoding silences: %w", err)}, nil, nil}
	}

	// Handle empty array.
	if len(silences) == 0 {
		return apiFuncResult{[]string{}, nil, nil, nil}
	}

	// Validate all silences before creating any (atomic semantics).
	for i, sil := range silences {
		if err := validateSilence(sil); err != nil {
			return apiFuncResult{
				nil,
				&apiError{
					errorBadData,
					fmt.Errorf("silence at index %d is invalid: %w", i, err),
				},
				nil,
				nil,
			}
		}
	}

	// Create all silences.
	ids := make([]string, 0, len(silences))
	for _, sil := range silences {
		id, err := api.silenceManager.CreateSilence(sil)
		if err != nil {
			return apiFuncResult{nil, &apiError{errorInternal, fmt.Errorf("error creating silence: %w", err)}, nil, nil}
		}
		ids = append(ids, id)
	}

	return apiFuncResult{ids, nil, nil, nil}
}

